        // Helper methods for Guna2 control configuration
        private void GunaTextBox(Guna.UI2.WinForms.Guna2TextBox tb, System.Drawing.Point location, System.Drawing.Size size)
        {
            tb.Animated = true;
            tb.BackColor = System.Drawing.Color.Transparent;
            tb.BorderColor = System.Drawing.Color.FromArgb(0, 200, 210);
            tb.BorderRadius = 8;
            tb.BorderThickness = 1;
            tb.Cursor = System.Windows.Forms.Cursors.IBeam;
            tb.DefaultText = "";
            tb.FillColor = System.Drawing.Color.FromArgb(255, 248, 252);
            tb.Font = new System.Drawing.Font("Segoe UI", 10F);
            tb.ForeColor = System.Drawing.Color.FromArgb(15, 23, 42);
            tb.HoverState.BorderColor = System.Drawing.Color.FromArgb(6, 148, 148);
            tb.Location = location;
            tb.Name = tb.Name;
            tb.SelectedText = "";
            tb.Size = size;
        }

        private void GunaReadOnlyTextBox(Guna.UI2.WinForms.Guna2TextBox tb, System.Drawing.Point location, System.Drawing.Size size)
        {
            GunaTextBox(tb, location, size);
            tb.ReadOnly = true;
            tb.ForeColor = System.Drawing.Color.FromArgb(107, 114, 128);
        }

        private void GunaMultiLineTextBox(Guna.UI2.WinForms.Guna2TextBox tb, System.Drawing.Point location, System.Drawing.Size size)
        {
            GunaTextBox(tb, location, size);
            tb.Multiline = true;
        }

        private void GunaCombo(Guna.UI2.WinForms.Guna2ComboBox combo, System.Drawing.Point location, System.Drawing.Size size, string[] items)
        {
            combo.BackColor = System.Drawing.Color.Transparent;
            combo.BorderColor = System.Drawing.Color.FromArgb(0, 200, 210);
            combo.BorderRadius = 8;
            combo.BorderThickness = 1;
            combo.DrawMode = System.Windows.Forms.DrawMode.OwnerDrawFixed;
            combo.DropDownStyle = System.Windows.Forms.ComboBoxStyle.DropDown;
            combo.FillColor = System.Drawing.Color.FromArgb(255, 248, 252);
            combo.Font = new System.Drawing.Font("Segoe UI", 10F);
            combo.ForeColor = System.Drawing.Color.FromArgb(15, 23, 42);
            combo.HoverState.BorderColor = System.Drawing.Color.FromArgb(6, 148, 148);
            combo.Items.AddRange(items);
            combo.Location = location;
            combo.Name = combo.Name;
            combo.Size = size;
        }

        private void GunaDate(Guna.UI2.WinForms.Guna2DateTimePicker dt, System.Drawing.Point location, System.Drawing.Size size)
        {
            dt.Animated = true;
            dt.BackColor = System.Drawing.Color.Transparent;
            dt.BorderColor = System.Drawing.Color.FromArgb(0, 200, 210);
            dt.BorderRadius = 8;
            dt.BorderThickness = 1;
            dt.Checked = true;
            dt.FillColor = System.Drawing.Color.FromArgb(255, 248, 252);
            dt.Font = new System.Drawing.Font("Segoe UI", 10F);
            dt.ForeColor = System.Drawing.Color.FromArgb(15, 23, 42);
            dt.Format = System.Windows.Forms.DateTimePickerFormat.Short;
            dt.Location = location;
            dt.MaxDate = new System.DateTime(2099, 12, 31, 0, 0, 0, 0);
            dt.MinDate = new System.DateTime(1950, 1, 1, 0, 0, 0, 0);
            dt.Name = dt.Name;
            dt.Size = size;
            dt.Value = System.DateTime.Today;
        }

